379→function matchPattern(pattern: string, input: string): boolean {
380→  // Simple glob matching
381→  if (pattern === "*") return true;
382→  if (pattern.endsWith("*")) {
383→    const prefix = pattern.slice(0, -1);
384→    return input.startsWith(prefix);
385→  }
386→  return pattern === input;
387→}
388→
389→function routeItem(typeOrTitle: string): { queue: string; priority: Priority; requiresApproval: boolean } {
390→  const config = loadRoutingConfig();
391→
392→  for (const rule of config.routes) {
393→    if (matchPattern(rule.pattern, typeOrTitle)) {
394→      return {
395→        queue: rule.queue,
396→        priority: rule.priority ?? config.defaults.priority,
397→        requiresApproval: rule.requiresApproval ?? false,
398→      };
399→    }
400→  }
401→
402→  return {
403→    queue: "approvals",
404→    priority: config.defaults.priority,
405→    requiresApproval: true,
406→  };
407→}
