409→export function loadQueueItems(queueName: string): QueueItem[] {
410→  const filePath = getQueueFilePath(queueName);
411→  if (!existsSync(filePath)) {
412→    return [];
413→  }
414→
415→  const content = readFileSync(filePath, "utf-8");
416→  const lines = content.trim().split("\n").filter(Boolean);
417→  let droppedLines = 0;
418→
419→  const items = lines.map((line, index) => {
420→    try {
421→      return JSON.parse(line) as QueueItem;
422→    } catch (err) {
423→      droppedLines++;
424→      console.error(`[QueueManager] Corrupt JSONL line ${index + 1} in ${queueName}.jsonl: ${err instanceof Error ? err.message : err}`);
425→      return null;
426→    }
427→  }).filter((item): item is QueueItem => item !== null);
428→
429→  if (droppedLines > 0) {
430→    console.error(`[QueueManager] WARNING: Dropped ${droppedLines} corrupt line(s) from ${queueName}.jsonl (${items.length} valid items loaded)`);
431→  }
432→
433→  return items;
434→}
