436→export function saveQueueItems(queueName: string, items: QueueItem[]): void {
437→  ensureDir(QUEUES_DIR);
438→  const filePath = getQueueFilePath(queueName);
439→  const content = items.map((item) => JSON.stringify(item)).join("\n");
440→  const tmpPath = filePath + ".tmp." + process.pid;
441→  writeFileSync(tmpPath, content + (content ? "\n" : ""));
442→  renameSync(tmpPath, filePath);
443→}
