445→export function appendQueueItem(queueName: string, item: QueueItem): void {
446→  ensureDir(QUEUES_DIR);
447→  const filePath = getQueueFilePath(queueName);
448→  appendFileSync(filePath, JSON.stringify(item) + "\n");
449→}
