453→ * Synchronous wrapper for CLI compatibility
454→ */
455→function loadState(): QueueState {
456→  // Use sync read for CLI commands (StateManager.load is async)
457→  if (!existsSync(STATE_FILE)) {
458→    return {
459→      lastUpdated: new Date().toISOString(),
460→      queues: [],
461→      stats: { totalItems: 0, totalProcessed: 0 },
