464→
465→  try {
466→    const raw = readFileSync(STATE_FILE, "utf-8");
467→    const parsed = JSON.parse(raw);
468→    // Remove internal version field if present
469→    const { _version, ...stateData } = parsed;
470→    const result = QueueStateSchema.safeParse(stateData);
471→    return result.success ? result.data : {
472→      lastUpdated: new Date().toISOString(),
473→      queues: [],
474→      stats: { totalItems: 0, totalProcessed: 0 },
475→    };
476→  } catch {
477→    return {
478→      lastUpdated: new Date().toISOString(),
479→      queues: [],
480→      stats: { totalItems: 0, totalProcessed: 0 },
481→    };
482→  }
483→}
